## Section1(not reported)
## Problem1(3.5.8.49)
## Author()
## Institution()
## Language(en-US)

DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "parserOneOf.pl",
  "contextFiniteSolutionSets.pl",
  "contextForm.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
do {
  ($m, $n, $b, $c) = random_subset(4,-9..-1,1..9);
  $p = $m + $n;
  $d = $b + $c;
} until ($p != 0 && $d != 0);
$x = list_random('a'..'n','p'..'z','A'..'D', 'F'..'N','P'..'T','V'..'Z');
Context()->variables->are($x => 'Real');
Context()->noreduce('(-x)+y', '(-x)-y');
$left = Formula("$m $x + $d + $n $x")->reduce;
$right = Formula("$b + $p $x + $c")->reduce;
Context("FiniteSolutionSets")->variables->are($x => 'Real');
#$solution = String("no real solutions")->cmp(typeMatch => Formula("{1}"));
$solution = OneOf(Compute("R"), String("infinitely many solutions"))->cmp(typeMatch => Formula("{1}"));
$leftsol[0] = Formula("($m+$n) $x + $d")->reduce;
$rightsol[0] = Formula("$p $x + ($b + $c)")->reduce;
$leftsol[1] = Formula("$d")->reduce;
$rightsol[1] = Formula("($b + $c)")->reduce;

############################################################
# Body
############################################################

BEGIN_PGML
Solve the equation for its variable.

[`[$left]=[$right]`]

[_]{$solution}{16}

END_PGML

############################################################
# Solution
############################################################

BEGIN_PGML_SOLUTION
We try to use the standard steps for solving an equation:

[```\newcommand{\amp}{&}
\begin{aligned}
[$left] \amp= [$right]\\
[$leftsol[0]] \amp= [$rightsol[0]]\\
[$leftsol[1]] \amp= [$rightsol[1]]
\end{aligned}
```]

This is an outright true equation, so all real numbers are solutions. The solution set is [`(-\infty,\infty)\text{,}`] which we can write as [`\mathbb{R}\text{.}`]

END_PGML_SOLUTION

############################################################
# End Problem
############################################################

ENDDOCUMENT();
